function numSteps(s) {
    let steps = 0, carry = 0;
    for (let i = s.length - 1; i > 0; --i) {
        let current = parseInt(s[i]) + carry;
        if (current == 1) {
            steps += 2;
            carry = 1;
        } else {
            steps += carry;
            carry = current;
        }
    }

    return steps + carry;
}
```

    1. Initialize the count of steps and carry to 0.
2. Iterate through the elements of the binary string from the least significant digit to the most significant digit.
3. In each iteration, add the carry and the current digit.
4. If the result is 1, increment the steps by 2 and update the carry to 1.
5. If the result is not 1, increment the steps by the previous carry and update the carry with the result.
6. Return the total number of steps taken plus the final carry.

