public int numSteps(String s) {
    int steps = 0, carry = 0;
    for (int i = s.length() - 1; i > 0; --i) {
        int current = s.charAt(i) - '0' + carry;
        if (current == 1) {
            steps += 2;
            carry = 1;
        } else {
            steps += carry;
            carry = current;
        }
    }

    return steps + carry;
}
```

